  1	import * as React from 'react';
  2	import { getLastLanguage } from '@odf/shared/utils';
  3	import {
  4	  IncompleteDataError,
  5	  TimeoutError,
  6	} from '@odf/shared/utils/error/http-error';
  7	import classNames from 'classnames';
  8	import * as _ from 'lodash-es';
  9	import { Trans } from 'react-i18next';
 10	import { Alert, Button } from '@patternfly/react-core';
 11	import { useCustomTranslation } from '../useCustomTranslationHook';
 12	import '../style.scss';
 13	
 14	export const Box: React.FC<BoxProps> = ({ children, className }) => (
 15	  <div className={classNames('odf-status-box', className)}>{children}</div>
 16	);
 17	
 18	export const LoadError: React.FC<LoadErrorProps> = ({
 19	  label,
 20	  className,
 21	  message,
 22	  canRetry = true,
 23	}) => {
 24	  const { t } = useCustomTranslation();
 25	  return (
 26	    <Box className={className}>
 27	      <div className="pf-v6-u-text-align-center odf-error-title">
 28	        {_.isString(message)
 29	          ? t('Error Loading {{label}}: {{message}}', {
 30	              label,
 31	              message,
 32	            })
 33	          : t('Error Loading {{label}}', { label })}
 34	      </div>
 35	      {canRetry && (
 36	        <div className="pf-v6-u-text-align-center">
 37	          <Trans t={t}>
 38	            Please{' '}
 39	            <Button
 40	              type="button"
 41	              onClick={window.location.reload.bind(window.location)}
 42	              variant="link"
 43	              isInline
 44	            >
 45	              try again
 46	            </Button>
 47	            .
 48	          </Trans>
 49	        </div>
 50	      )}
 51	    </Box>
 52	  );
 53	};
 54	LoadError.displayName = 'LoadError';
 55	
 56	export const Loading: React.FC<LoadingProps> = ({ className }) => (
 57	  <div
 58	    className={classNames('odf-m-loader', className)}
 59	    data-test="loading-indicator"
 60	  >
 61	    <div className="odf-m-loader-dot__one" />
 62	    <div className="odf-m-loader-dot__two" />
 63	    <div className="odf-m-loader-dot__three" />
 64	  </div>
 65	);
 66	Loading.displayName = 'Loading';
 67	
 68	export const LoadingInline: React.FC<{}> = () => (
 69	  <Loading className="odf-m-loader--inline" />
 70	);
 71	LoadingInline.displayName = 'LoadingInline';
 72	
 73	export const LoadingBox: React.FC<LoadingBoxProps> = ({
 74	  className,
 75	  message,
 76	}) => (
 77	  <Box className={classNames('odf-status-box--loading', className)}>
 78	    <Loading />
 79	    {message && (
 80	      <div className="odf-status-box__loading-message">{message}</div>
 81	    )}
 82	  </Box>
 83	);
 84	LoadingBox.displayName = 'LoadingBox';
 85	
 86	export const EmptyBox: React.FC<EmptyBoxProps> = ({ label }) => {
 87	  const { t } = useCustomTranslation();
 88	  return (
 89	    <Box>
 90	      <div data-test="empty-message" className="pf-v6-u-text-align-center">
 91	        {label ? t('No {{label}} found', { label }) : t('Not found')}
 92	      </div>
 93	    </Box>
 94	  );
 95	};
 96	EmptyBox.displayName = 'EmptyBox';
 97	
 98	export const MsgBox: React.FC<MsgBoxProps> = ({
 99	  title,
100	  detail,
101	  className = '',
102	}) => (
103	  <Box className={className}>
104	    {title && (
105	      <div className="odf-status-box__title" data-test="msg-box-title">
106	        {title}
107	      </div>
108	    )}
109	    {detail && (
110	      <div
111	        className="pf-v6-u-text-align-center odf-status-box__detail"
112	        data-test="msg-box-detail"
113	      >
114	        {detail}
115	      </div>
116	    )}
117	  </Box>
118	);
119	MsgBox.displayName = 'MsgBox';
120	
121	export const AccessDenied: React.FC<AccessDeniedProps> = ({ message }) => {
122	  const { t } = useCustomTranslation();
123	  return (
124	    <div>
125	      <Box className="pf-v6-u-text-align-center">
126	        <MsgBox
127	          title={t('Restricted Access')}
128	          detail={t(
129	            "You don't have access to this section due to cluster policy."
130	          )}
131	        />
132	      </Box>
133	      {_.isString(message) && (
134	        <Alert
135	          isInline
136	          className="odf-alert"
137	          variant="danger"
138	          title={t('Error details')}
139	        >
140	          {message}
141	        </Alert>
142	      )}
143	    </div>
144	  );
145	};
146	AccessDenied.displayName = 'AccessDenied';
147	
148	const Data: React.FC<DataProps> = ({
149	  NoDataEmptyMsg,
150	  EmptyMsg,
151	  label,
152	  data,
153	  unfilteredData,
154	  children,
155	}) => {
156	  if (NoDataEmptyMsg && _.isEmpty(unfilteredData)) {
157	    return (
158	      <div className="odf-loading-box loading-box__loaded">
159	        {NoDataEmptyMsg ? <NoDataEmptyMsg /> : <EmptyBox label={label} />}
160	      </div>
161	    );
162	  }
163	
164	  if (!data || _.isEmpty(data)) {
165	    return (
166	      <div className="odf-loading-box loading-box__loaded">
167	        {EmptyMsg ? <EmptyMsg /> : <EmptyBox label={label} />}
168	      </div>
169	    );
170	  }
171	  return <div className="odf-loading-box loading-box__loaded">{children}</div>;
172	};
173	Data.displayName = 'Data';
174	
175	export const StatusBox: React.FC<StatusBoxProps> = (props) => {
176	  const { loadError, loaded, skeleton, data, ...dataProps } = props;
177	  const { t } = useCustomTranslation();
178	
179	  if (loadError) {
180	    const status = _.get(loadError, 'response.status');
181	    if (status === 404) {
182	      return (
183	        <div className="odf-m-pane__body">
184	          <h1 className="odf-m-pane__heading odf-m-pane__heading">
185	            {_.isString(loadError.message)
186	              ? t('404 Not Found: {{ message }}', {
187	                  message: loadError.message,
188	                })
189	              : t('404: Not Found')}
190	          </h1>
191	        </div>
192	      );
193	    }
194	    if (status === 403) {
195	      return <AccessDenied message={loadError.message} />;
196	    }
197	
198	    if (loadError instanceof IncompleteDataError && !_.isEmpty(data)) {
199	      return (
200	        <Data data={data} {...dataProps}>
201	          <Alert
202	            variant="info"
203	            isInline
204	            title={t(
205	              '{{labels}} content is not available in the catalog at this time due to loading failures.',
206	              {
207	                // @ts-ignore
208	                labels: new Intl.ListFormat(getLastLanguage() || 'en', {
209	                  style: 'long',
210	                  type: 'conjunction',
211	                }).format(loadError.labels),
212	              }
213	            )}
214	          />
215	          {props.children}
216	        </Data>
217	      );
218	    }
219	
220	    if (loaded && loadError instanceof TimeoutError) {
221	      return (
222	        <Data data={data} {...dataProps}>
223	          <div className="odf-m-timeout-error text-muted">
224	            {t('Timed out fetching new data. The data below is stale.')}
225	          </div>
226	          {props.children}
227	        </Data>
228	      );
229	    }
230	
231	    return (
232	      <LoadError
233	        message={loadError.message}
234	        label={props.label}
235	        className="odf-loading-box loading-box__errored"
236	      />
237	    );
238	  }
239	
240	  if (!loaded) {
241	    return skeleton ? (
242	      <>{skeleton}</>
243	    ) : (
244	      <LoadingBox className="odf-loading-box loading-box__loading" />
245	    );
246	  }
247	  return <Data data={data} {...dataProps} />;
248	};
249	StatusBox.displayName = 'StatusBox';
250	
251	type BoxProps = {
252	  children: React.ReactNode;
253	  className?: string;
254	};
255	
256	type LoadErrorProps = {
257	  label: string;
258	  className?: string;
259	  message?: string;
260	  canRetry?: boolean;
261	};
262	
263	type LoadingProps = {
264	  className?: string;
265	};
266	
267	type LoadingBoxProps = {
268	  className?: string;
269	  message?: string;
270	};
271	
272	type EmptyBoxProps = {
273	  label?: string;
274	};
275	
276	type MsgBoxProps = {
277	  title?: string;
278	  detail?: React.ReactNode;
279	  className?: string;
280	};
281	
282	type AccessDeniedProps = {
283	  message?: string;
284	};
285	
286	type DataProps = {
287	  NoDataEmptyMsg?: React.ComponentType;
288	  EmptyMsg?: React.ComponentType;
289	  label?: string;
290	  unfilteredData?: any;
291	  data?: any;
292	  children?: React.ReactNode;
293	};
294	
295	type StatusBoxProps = {
296	  label?: string;
297	  loadError?: any;
298	  loaded?: boolean;
299	  data?: any;
300	  unfilteredData?: any;
301	  skeleton?: React.ReactNode;
302	  NoDataEmptyMsg?: React.ComponentType;
303	  EmptyMsg?: React.ComponentType;
304	  children?: React.ReactNode;
305	};

